 1→<!DOCTYPE html>
 2→<html lang="en">
 3→<head>
 4→    <meta charset="UTF-8">
 5→    <meta name="viewport" content="width=device-width, initial-scale=1.0">
 6→    <title>{% block title %}Todo List{% endblock %}</title>
 7→    <link rel="stylesheet" href="/static/css/main.css">
 8→    {% block head %}{% endblock %}
 9→</head>
10→<body class="page-layout" hx-boost="true">
11→    <a href="#main-content" class="skip-link">Skip to main content</a>
12→    <header>
13→        <nav class="container" aria-label="Main navigation">
14→            {% block nav %}{% endblock %}
15→        </nav>
16→    </header>
17→    <main id="main-content" class="container">
18→        {% block content %}{% endblock %}
19→    </main>
20→    <footer class="container">
21→        {% block footer %}{% endblock %}
22→    </footer>
23→    <div aria-live="polite" aria-atomic="true" id="live-region" class="visually-hidden"></div>
24→    <script src="/static/js/htmx.min.js"></script>
25→    <script>
26→    document.body.addEventListener("announce", function(e) {
27→        var region = document.getElementById("live-region");
28→        if (region && e.detail && e.detail.value) {
29→            region.textContent = e.detail.value;
30→        }
31→    });
32→    </script>
33→    {% block scripts %}{% endblock %}
34→</body>
35→</html>
36→

