 73→    let app = spawn_app().await;
 74→    let client =
 75→        register_and_login(&app.address, "dashboard@example.com", "securepassword123").await;
 76→
 77→    let response = client
 78→        .get(format!("{}/dashboard", &app.address))
 79→        .send()
 80→        .await
 81→        .expect("Failed to execute request");
 82→
 83→    assert_eq!(response.status().as_u16(), 200);
 84→
 85→    let body = response.text().await.unwrap();
 86→
 87→    // Page structure
 88→    assert!(body.contains("<h1>"), "Missing page heading");
 89→    assert!(
 90→        body.contains("Dashboard"),
 91→        "Dashboard heading should be present"
 92→    );
 93→}
