 95→#[tokio::test]
 96→async fn dashboard_has_gtd_navigation_links() {
 97→    let app = spawn_app().await;
 98→    let client = register_and_login(&app.address, "dashnav@example.com", "securepassword123").await;
 99→
100→    let response = client
101→        .get(format!("{}/dashboard", &app.address))
102→        .send()
103→        .await
104→        .expect("Failed to execute request");
105→
106→    assert_eq!(response.status().as_u16(), 200);
107→
108→    let body = response.text().await.unwrap();
109→
110→    // Navigation links for all GTD lists
111→    assert!(body.contains("href=\"/inbox\""), "Missing link to /inbox");
112→    assert!(
113→        body.contains("href=\"/next-actions\""),
114→        "Missing link to /next-actions"
