116→    assert!(
117→        body.contains("href=\"/projects\""),
118→        "Missing link to /projects"
119→    );
120→    assert!(
121→        body.contains("href=\"/waiting-for\""),
122→        "Missing link to /waiting-for"
123→    );
124→    assert!(
125→        body.contains("href=\"/someday-maybe\""),
126→        "Missing link to /someday-maybe"
127→    );
128→    assert!(body.contains("href=\"/review\""), "Missing link to /review");
129→
130→    // Nav uses proper landmark
131→    assert!(
132→        body.contains("aria-label=\"GTD lists\""),
